export default "v-scroll{--track-width:6px;--thumb-color:#00000040;--thumb-hover-color:#00000073;--thumb-active-color:#000000a6;--track-color:transparent;--track-hover-color:#0000000f;--track-padding:3px;display:block;position:relative;overflow:hidden}v-scroll::part(track){width:var(--track-width);background:var(--track-color);border-radius:calc(var(--track-width) / 2);z-index:10;transition:background .2s,width .2s;position:absolute;top:0;bottom:0;right:0}v-scroll::part(track):hover,v-scroll::part(track-active){width:calc(var(--track-width) * 1.5);background:var(--track-hover-color)}v-scroll::part(bar){background:var(--thumb-color);border-radius:calc(var(--track-width) / 2);cursor:grab;user-select:none;min-height:16px;transition:background .15s,border-radius .2s;position:absolute;left:0;right:0}v-scroll::part(bar):hover{background:var(--thumb-hover-color)}v-scroll::part(bar-active){background:var(--thumb-active-color);cursor:grabbing;border-radius:calc(var(--track-width) / 4)}";
